import React, { useState } from 'react';
import { StatSummary } from '../types';
import { 
  Chart as ChartJS, CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend, ArcElement, PointElement, LineElement 
} from 'chart.js';
import { Bar, Doughnut } from 'react-chartjs-2';
import { Activity, TrendingUp, MousePointerClick, Clock } from 'lucide-react';

ChartJS.register(CategoryScale, LinearScale, BarElement, ArcElement, PointElement, LineElement, Title, Tooltip, Legend);

const Dashboard: React.FC = () => {
  const stats = {
    totalAlerts: 100,
    criticalAlerts: 62,
    avgResolutionTime: 1052,
    activeAnalysts: 0,
    falsePositiveRate: 0.0,
    mttr: 1052,
  };

  // Mock Data for "Top Vecteurs de Menaces"
  const barData = {
    labels: ['Autre', 'Malware/Trojan', 'Injection SQL', 'DDoS', 'Phishing', 'Brute Force'],
    datasets: [{
      data: [80, 15, 12, 0, 0, 0],
      backgroundColor: ['#ef4444', '#f97316', '#8b5cf6', '#e5e7eb', '#e5e7eb', '#e5e7eb'],
      borderWidth: 0,
      barThickness: 16,
      borderRadius: 4,
    }],
  };

  const barOptions = {
    indexAxis: 'y' as const,
    responsive: true,
    maintainAspectRatio: false,
    plugins: { legend: { display: false } },
    scales: {
      x: { display: true, grid: { display: false, drawBorder: false }, ticks: { stepSize: 25, color: '#9ca3af' } },
      y: { grid: { display: false, drawBorder: false }, ticks: { color: '#6b7280', font: { size: 11 } } },
    },
  };

  // Mock Data for "Sévérité"
  const doughnutData = {
    labels: ['Critique', 'Élevée', 'Moyenne', 'Faible'],
    datasets: [{
      data: [60, 25, 10, 5], // Approximate representation of the chart
      backgroundColor: ['#ef4444', '#f97316', '#eab308', '#3b82f6'],
      borderWidth: 5,
      borderColor: '#ffffff',
      cutout: '75%',
    }],
  };

  const doughnutOptions = {
    responsive: true, maintainAspectRatio: false,
    plugins: { 
      legend: { display: false }
    }
  };

  return (
    <div className="space-y-6">
      {/* Metrics Row */}
      <div className="grid gap-6 md:grid-cols-4">

        <div className="rounded-2xl border border-gray-100 bg-white p-6 shadow-sm">
          <div className="text-3xl font-extrabold text-[#0f172a]">{stats.totalAlerts}</div>
          <div className="mt-1 flex items-center justify-between">
            <h3 className="text-sm font-semibold tracking-wide text-[#334155]">Alertes Actives</h3>
          </div>
          <p className="mt-1 text-[11px] font-medium text-gray-400">{stats.criticalAlerts} critiques à traiter</p>
        </div>

        <div className="rounded-2xl border border-gray-100 bg-white p-6 shadow-sm">
          <div className="text-3xl font-extrabold text-[#0f172a]">94.36%</div>
          <div className="mt-1 flex items-center justify-between">
            <h3 className="text-sm font-semibold tracking-wide text-[#334155]">Intelligence IA</h3>
          </div>
          <p className="mt-1 text-[11px] font-medium text-gray-400">Précision (UNSW-NB15)</p>
        </div>

        <div className="rounded-2xl border border-gray-100 bg-white p-6 shadow-sm">
          <div className="text-3xl font-extrabold text-[#0f172a]">{stats.mttr} min</div>
          <div className="mt-1 flex items-center justify-between">
            <h3 className="text-sm font-semibold tracking-wide text-[#334155]">MTTR Moyen</h3>
          </div>
          <p className="mt-1 text-[11px] font-medium text-gray-400">Temps Moyen de Résolution</p>
        </div>

        <div className="rounded-2xl border border-gray-100 bg-white p-6 shadow-sm">
          <div className="text-3xl font-extrabold text-[#0f172a]">{stats.falsePositiveRate.toFixed(1)}%</div>
          <div className="mt-1 flex items-center justify-between">
            <h3 className="text-sm font-semibold tracking-wide text-[#334155]">Faux Positifs</h3>
          </div>
          <p className="mt-1 text-[11px] font-medium text-gray-400">Taux de filtrage actuel</p>
        </div>

      </div>

      {/* Charts Row */}
      <div className="grid gap-6 md:grid-cols-3">
        {/* Horizontal Bar Chart */}
        <div className="md:col-span-2 rounded-2xl border border-gray-100 bg-white p-6 shadow-[0_4px_20px_-2px_rgba(0,0,0,0.05)]">
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center space-x-2 text-[#4f46e5]">
              <Activity className="h-5 w-5" />
              <h3 className="font-bold text-lg text-[#1e293b]">Top Vecteurs de Menaces</h3>
            </div>
            <div className="flex items-center text-xs font-semibold tracking-wide text-gray-400">
              <MousePointerClick className="h-3 w-3 mr-1" />
              Cliquable
            </div>
          </div>
          <div className="h-[250px] w-full pr-4">
            <Bar data={barData} options={barOptions} />
          </div>
        </div>

        {/* Doughnut Chart */}
        <div className="rounded-2xl border border-gray-100 bg-white p-6 shadow-[0_4px_20px_-2px_rgba(0,0,0,0.05)]">
          <div className="flex items-center justify-between mb-8">
            <div className="flex items-center space-x-2 text-[#3b82f6]">
              <Clock className="h-5 w-5" />
              <h3 className="font-bold text-lg text-[#1e293b]">Sévérité</h3>
            </div>
            <div className="flex items-center text-xs font-semibold tracking-wide text-gray-400">
              <MousePointerClick className="h-3 w-3 mr-1" />
              Cliquable
            </div>
          </div>
          <div className="h-[180px] w-full relative mb-6">
            <Doughnut data={doughnutData} options={doughnutOptions} />
          </div>
          {/* Custom Legend */}
          <div className="flex flex-wrap justify-center gap-x-4 gap-y-2 text-xs font-bold text-gray-500">
            <div className="flex items-center"><span className="w-2.5 h-2.5 rounded-full bg-red-500 mr-1.5 border border-white"></span>Critique</div>
            <div className="flex items-center"><span className="w-2.5 h-2.5 rounded-full bg-blue-500 mr-1.5 border border-white"></span>Faible</div>
            <div className="flex items-center"><span className="w-2.5 h-2.5 rounded-full bg-yellow-500 mr-1.5 border border-white"></span>Moyenne</div>
            <div className="flex items-center"><span className="w-2.5 h-2.5 rounded-full bg-orange-500 mr-1.5 border border-white"></span>Élevée</div>
          </div>
        </div>
      </div>

      {/* Bottom Line Chart */}
      <div className="rounded-2xl border border-gray-100 bg-white p-6 shadow-sm overflow-hidden h-[150px]">
        <div className="flex items-center space-x-2 text-[#10b981] mb-2">
          <TrendingUp className="h-5 w-5" />
          <h3 className="font-bold text-lg text-[#1e293b]">Tendance de Risque (Temps Réel)</h3>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
